import{_ as e,c as o,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Быстрый старт: Начало работы с Plannotator | plannotator","description":"Изучите быстрый старт Plannotator. Узнайте основные функции за 5 минут, завершите установку и настройку плагина Claude Code или OpenCode.","frontmatter":{"title":"Быстрый старт: Начало работы с Plannotator | plannotator","sidebarTitle":"Быстрый старт за 5 минут","subtitle":"Быстрый старт: Начало работы с Plannotator","description":"Изучите быстрый старт Plannotator. Узнайте основные функции за 5 минут, завершите установку и настройку плагина Claude Code или OpenCode.","order":1},"headers":[],"relativePath":"ru/backnotprop/plannotator/start/index.md","filePath":"ru/backnotprop/plannotator/start/index.md"}'),l={name:"ru/backnotprop/plannotator/start/index.md"};function r(d,a,i,s,c,p){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="быстрыи-старт" tabindex="-1">Быстрый старт <a class="header-anchor" href="#быстрыи-старт" aria-label="Permalink to &quot;Быстрый старт&quot;">​</a></h1><p>Этот раздел поможет вам начать работу с Plannotator с нуля. Вы узнаете, что такое Plannotator, какие проблемы он решает, и завершите установку и настройку в используемом вами AI Coding Agent (Claude Code или OpenCode).</p><h2 id="содержание-раздела" tabindex="-1">Содержание раздела <a class="header-anchor" href="#содержание-раздела" aria-label="Permalink to &quot;Содержание раздела&quot;">​</a></h2><div class="grid-cards"><h3 id="быстрыи-старт-1" tabindex="-1"><a href="./getting-started/">Быстрый старт</a> <a class="header-anchor" href="#быстрыи-старт-1" aria-label="Permalink to &quot;[Быстрый старт](./getting-started/)&quot;">​</a></h3><p>Узнайте основные функции и сценарии использования Plannotator, завершите первое знакомство за 5 минут. Подходит для всех новых пользователей в качестве первого урока.</p><h3 id="установка-плагина-claude-code" tabindex="-1"><a href="./installation-claude-code/">Установка плагина Claude Code</a> <a class="header-anchor" href="#установка-плагина-claude-code" aria-label="Permalink to &quot;[Установка плагина Claude Code](./installation-claude-code/)&quot;">​</a></h3><p>Установите и настройте плагин Plannotator в Claude Code. Поддерживает два способа: систему плагинов и ручные Hook, включая локальную и удалённую конфигурацию.</p><h3 id="установка-плагина-opencode" tabindex="-1"><a href="./installation-opencode/">Установка плагина OpenCode</a> <a class="header-anchor" href="#установка-плагина-opencode" aria-label="Permalink to &quot;[Установка плагина OpenCode](./installation-opencode/)&quot;">​</a></h3><p>Установите и настройте плагин Plannotator в OpenCode, активируйте tool <code>submit_plan</code> и команду <code>/plannotator-review</code>.</p></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Рекомендуемый порядок</p><ol><li><strong>Сначала прочитайте <a href="./getting-started/">Быстрый старт</a></strong>: Узнайте, что такое Plannotator, что он может делать, сформируйте общее понимание</li><li><strong>Затем выберите руководство по установке</strong>: Выберите соответствующее руководство по установке в зависимости от используемого вами AI Coding Agent <ul><li>Используете Claude Code → <a href="./installation-claude-code/">Установка плагина Claude Code</a></li><li>Используете OpenCode → <a href="./installation-opencode/">Установка плагина OpenCode</a></li></ul></li></ol></div><p>После завершения установки вы можете начать использовать Plannotator для проверки планов и кода.</p><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этого раздела продолжайте изучать <strong><a href="./../platforms/">Функции платформы</a></strong>, чтобы освоить полное использование проверки планов и кода:</p><ul><li>Основы проверки планов: одобрение, отклонение, добавление комментариев</li><li>Аннотирование изображений: прикрепление снимков экрана и аннотирование в планах</li><li>Проверка кода: визуализация Git diff, добавление комментариев на уровне строк</li></ul>',10)])])}const C=e(l,[["render",r]]);export{u as __pageData,C as default};
